// --- send_email branch ---
// Fetch email template from Supabase, build email payload for Send Email subworkflow.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Extract Payload').first().json;
const { stepConfig, triggerPayload } = input;

const templateId = stepConfig.template_id;
const recipientField = stepConfig.recipient || 'notification_email';

// Supabase config — uses service role key
const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY || $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabaseGet(table, filters) {
  const params = new URLSearchParams();
  for (const [key, value] of Object.entries(filters)) {
    params.append(key, `eq.${value}`);
  }
  params.append('limit', '1');

  const url = `${SUPABASE_URL}/rest/v1/${table}?${params.toString()}`;

  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
      }
    }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(body));
        } catch (e) {
          reject(new Error(`Parse error: ${body}`));
        }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  // Fetch the response to get notification_email from survey_link
  const responseId = triggerPayload.responseId;
  const responses = await supabaseGet('responses', { id: responseId });
  if (!responses.length) throw new Error(`Response ${responseId} not found`);
  const response = responses[0];

  // Fetch survey link for notification email
  const surveyLinks = await supabaseGet('survey_links', { id: response.survey_link_id });
  if (!surveyLinks.length) throw new Error(`Survey link ${response.survey_link_id} not found`);
  const surveyLink = surveyLinks[0];

  // Fetch email template if template_id provided
  let subject = stepConfig.subject || 'Notification';
  let html = stepConfig.html_body || '<p>Notification</p>';

  if (templateId) {
    const templates = await supabaseGet('email_templates', { id: templateId });
    if (templates.length && templates[0].html_body) {
      subject = templates[0].subject || subject;
      html = templates[0].html_body;
    }
  }

  // Determine recipient
  let to = stepConfig.to;
  if (!to) {
    to = surveyLink[recipientField] || surveyLink.notification_email;
  }

  if (!to) throw new Error('No recipient email resolved');

  return {
    to,
    subject,
    html,
    tenant_id: response.tenant_id,
    _stepExecutionId: input.stepExecutionId,
    _callbackUrl: input.callbackUrl
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// --- ai_action branch ---
// Call AI model (Anthropic API) with prompt from stepConfig.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Extract Payload').first().json;
const { stepConfig, triggerPayload } = input;

const prompt = stepConfig.prompt || 'Analyze the following data.';
const model = stepConfig.model || 'claude-haiku-4-5-20250710';
const maxTokens = stepConfig.max_tokens || 1000;
const temperature = stepConfig.temperature || 0.3;

// Build system + user message
const systemPrompt = stepConfig.system_prompt || 'You are a helpful assistant. Respond in JSON format when asked.';
const userMessage = `${prompt}\n\nContext: ${JSON.stringify(triggerPayload)}`;

const ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY || $env.ANTHROPIC_API_KEY;

try {
  const postData = JSON.stringify({
    model,
    max_tokens: maxTokens,
    temperature,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  });

  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.anthropic.com',
      path: '/v1/messages',
      method: 'POST',
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData)
      }
    }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(body);
          if (res.statusCode >= 400) {
            reject(new Error(`Anthropic API error ${res.statusCode}: ${JSON.stringify(parsed)}`));
          } else {
            resolve(parsed);
          }
        } catch (e) {
          reject(new Error(`Parse error: ${body}`));
        }
      });
    });
    req.on('error', reject);
    req.write(postData);
    req.end();
  });

  // Extract text content (handle thinking blocks)
  const textBlock = result.content.find(c => c.type === 'text');
  const aiResponse = textBlock ? textBlock.text : JSON.stringify(result.content);

  return {
    ai_response: aiResponse,
    model: result.model,
    usage: result.usage,
    _stepExecutionId: input.stepExecutionId,
    _callbackUrl: input.callbackUrl
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Prepare delay output with metadata for callback
const input = $('Extract Payload').first().json;
return {
  delay_completed: true,
  duration_minutes: input.stepConfig.duration_minutes,
  _stepExecutionId: input.stepExecutionId,
  _callbackUrl: input.callbackUrl
};

// Merge outputs from all branches and prepare callback payload.
// Only one branch will have data — the others will be empty.

const Sentry = require('@sentry/node');

let output = {};
let stepExecutionId, callbackUrl;

try {
  // Try each branch — only one will have items
  const branches = [
    { name: "Call 'Send Email'", key: 'email_result' },
    { name: 'Call AI Model', key: 'ai_result' },
    { name: 'Delay Output', key: 'delay_result' }
  ];

  for (const branch of branches) {
    try {
      const items = $(branch.name).all();
      if (items.length > 0) {
        const data = items[0].json;
        stepExecutionId = data._stepExecutionId;
        callbackUrl = data._callbackUrl;
        // Remove internal fields from output
        const { _stepExecutionId, _callbackUrl, ...rest } = data;
        output = rest;
        break;
      }
    } catch (e) {
      // Branch not executed — skip
    }
  }

  // Fallback: get from original payload if branches didn't set it
  if (!stepExecutionId) {
    const original = $('Extract Payload').first().json;
    stepExecutionId = original.stepExecutionId;
    callbackUrl = original.callbackUrl;
  }

  return {
    step_execution_id: stepExecutionId,
    status: 'completed',
    output_payload: output,
    _callbackUrl: callbackUrl
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Error handler — called when any branch fails.
// Sends failure callback to CMS workflow engine.

const Sentry = require('@sentry/node');

const input = $('Extract Payload').first().json;
const errorMessage = $input.first().json?.error?.message
  || $input.first().json?.message
  || 'Unknown error in n8n workflow execution';

Sentry.captureException(new Error(`[Workflow Action Executor] Step failed: ${errorMessage}`));
await Sentry.flush(2000);

return {
  step_execution_id: input.stepExecutionId,
  status: 'failed',
  error: errorMessage,
  _callbackUrl: input.callbackUrl
};

// Unsupported step type handler
const input = $('Extract Payload').first().json;
return {
  step_execution_id: input.stepExecutionId,
  status: 'failed',
  error: `Unsupported step type: ${input.stepType}`,
  _callbackUrl: input.callbackUrl
};
